#### 2.8 GraphQL Schema

```graphql
# call.graphqls
type Call {
    id: ID!
    caller: SimpleUser!
    callee: SimpleUser!
    status: CallStatus!
    startedAt: String
    endedAt: String
    durationSeconds: Int
    createdAt: String!
}

enum CallStatus {
    INITIATED
    RINGING
    CONNECTED
    ENDED
    MISSED
}

input InitiateCallInput {
    calleeId: ID!
}

extend type Query {
    callHistory(limit: Int, offset: Int): [Call!]!
    call(callId: ID!): Call
}

extend type Mutation {
    initiateCall(input: InitiateCallInput!): Call!
    acceptCall(callId: ID!): Call!
    endCall(callId: ID!): Call!
}
